import re, collections, hashlib
root=Path('shaders/trigonometric_and_transcendental')
funcs=collections.defaultdict(list)
for p in root.rglob('*.frag'):
    text=p.read_text()
    for m in re.finditer(r'(?ms)^(?:float|vec2|vec3)\s+(\w+)\s*\([^)]*\)\s*\{.*?^\}', text):
        name=m.group(1)
        body=re.sub(r'\s+', ' ', m.group(0)).strip()
        funcs[(name, hashlib.sha1(body.encode()).hexdigest())].append(str(p))
for (name,h), paths in sorted(funcs.items()):
    if len(paths)>1:
        print(name, len(paths))
        for p in paths: print(' ',p)
